    public java.util.concurrent.CompletableFuture<Object> initializeClient()
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            try
            {
                (this.handleBuilderFeeApproval()).join();
            } catch(Exception e)
            {
                return false;
            }
            return true;
        });

    }

    public java.util.concurrent.CompletableFuture<Object> handleBuilderFeeApproval()
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            if (Helpers.isTrue(this.isSandboxModeEnabled))
            {
                return false;
            }
            Object buildFee = this.safeBool(this.options, "builderFee", true);
            if (!Helpers.isTrue(buildFee))
            {
                return false;  // skip if builder fee is not enabled
            }
            Object approvedBuilderFee = this.safeBool(this.options, "approvedBuilderFee", false);
            if (Helpers.isTrue(approvedBuilderFee))
            {
                return true;  // skip if builder fee is already approved
            }
            try
            {
                Object builder = this.safeString(this.options, "builderCode", "CCXT"); // case sensitive
                Object maxFeeRate = this.safeString(this.options, "feeRate", "0.01");
                (this.approveBuilderCode(builder, maxFeeRate)).join();
                Helpers.addElementToObject(this.options, "approvedBuilderFee", true);
            } catch(Exception e)
            {
                Helpers.addElementToObject(this.options, "builderFee", false); // disable builder fee if an error occurs
            }
            return true;
        });

    }

    /**
     * @method
     * @name pacifica#fetchMarkets
     * @description retrieves data on all markets for pacifica
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} an array of objects representing market data
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(this.checkRequiredCredentials(false)))
            {
                (this.initializeClient()).join();
                (this.loadAccountSettings()).join();
            }
            Object swapMarkets = (this.fetchSwapMarkets(parameters)).join();
            return swapMarkets;
        });

    }

