    /**
     * @method
     * @name pacifica#fetchLeverage
     * @description fetch the set leverage for a market
     * @param {string} symbol  unified symbol of the market
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.account] will default to walletAddress if not provided
     * @returns {object} a [leverage structure]{@link https://docs.ccxt.com/?id=leverage-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchLeverage(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadAccountSettings()).join();
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object userAccount = null;
            var userAccountparametersVariable = this.handleOriginAndSingleAddress("fetchLeverage", parameters);
            userAccount = ((java.util.List<Object>) userAccountparametersVariable).get(0);
            parameters = ((java.util.List<Object>) userAccountparametersVariable).get(1);
            Object cacheAddress = this.walletAddress;
            Object settings = null;
            if (Helpers.isTrue(Helpers.isEqual(userAccount, cacheAddress)))
            {
                settings = this.handleOption("fetchLeverage", "settings", null);
            } else
            {
                final Object finalUserAccount = userAccount;
                Object request = new java.util.HashMap<String, Object>() {{
                    put( "account", finalUserAccount );
                }};
                settings = (this.fetchAccountSettings(this.extend(request, parameters))).join();
            }
            Object setting = this.safeDict(settings, symbol, null);
            if (Helpers.isTrue(Helpers.isEqual(setting, null)))
            {
                // NOTE: Upon account creation, all markets have margin settings default to cross margin and leverage default to max.
                // When querying this endpoint, all markets with default margin and leverage settings on this account will return blank.
                return this.parseLeverageFromMarket(market);
            } else
            {
                return this.parseLeverageFromSetting(symbol, setting);
            }
        });

    }

    public Object parseLeverageFromSetting(Object symbol, Object setting)
    {
        // {
        //   "WLFI/USDC:USDC": {
        //       "symbol": "WLFI",
        //       "isolated": false,
        //       "leverage": 5,
        //       "created_at": 1758085929703,
        //       "updated_at": 1758086074002
        //    },
        // }
        Object isIsolated = this.safeBool(setting, "isolated", false);
        Object leverage = this.safeInteger(setting, "leverage");
        Object marginMode = ((Helpers.isTrue(isIsolated))) ? "isolated" : "cross";
        return new java.util.HashMap<String, Object>() {{
            put( "info", setting );
            put( "symbol", symbol );
            put( "marginMode", marginMode );
            put( "longLeverage", leverage );
            put( "shortLeverage", leverage );
        }};
    }

    public Object parseLeverageFromMarket(Object market)
    {
        Object marketLimits = this.safeDict(market, "limits", new java.util.HashMap<String, Object>() {{}});
        Object leverageLimits = this.safeDict(marketLimits, "leverage", new java.util.HashMap<String, Object>() {{}});
        return new java.util.HashMap<String, Object>() {{
            put( "info", market );
            put( "symbol", PacificaCore.this.safeString(market, "symbol") );
            put( "marginMode", PacificaCore.this.handleOption("fetchLeverage", "defaultMarginMode", "cross") );
            put( "longLeverage", PacificaCore.this.safeInteger(leverageLimits, "max") );
            put( "shortLeverage", PacificaCore.this.safeInteger(leverageLimits, "max") );
        }};
    }

