    public Object parseFundingRate(Object info, Object... optionalArgs)
    {
        //
        //      {
        //         "funding": "0.00010529",
        //         "mark": "1.084819",
        //         "mid": "1.08615",
        //         "next_funding": "0.00011096",
        //         "open_interest": "3634796",
        //         "oracle": "1.084524",
        //         "symbol": "XPL",
        //         "timestamp": 1759222967974,
        //         "volume_24h": "20896698.0672",
        //         "yesterday_price": "1.3412"
        //       }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(info, "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object funding = this.safeNumber(info, "funding");
        Object markPx = this.safeNumber(info, "mark");
        Object oraclePx = this.safeNumber(info, "oracle");
        Object nextFundingRate = this.safeNumber(info, "next_funding");
        Object timestamp = this.safeInteger(info, "timestamp");
        Object fundingTimestamp = Helpers.multiply(Helpers.multiply(Helpers.multiply((Helpers.add((Math.floor(Double.parseDouble(Helpers.toString(Helpers.divide(Helpers.divide(Helpers.divide(this.milliseconds(), 60), 60), 1000))))), 1)), 60), 60), 1000);
        return new java.util.HashMap<String, Object>() {{
            put( "info", info );
            put( "symbol", symbol );
            put( "markPrice", markPx );
            put( "indexPrice", oraclePx );
            put( "interestRate", null );
            put( "estimatedSettlePrice", null );
            put( "timestamp", timestamp );
            put( "datetime", PacificaCore.this.iso8601(timestamp) );
            put( "fundingRate", funding );
            put( "fundingTimestamp", fundingTimestamp );
            put( "fundingDatetime", PacificaCore.this.iso8601(fundingTimestamp) );
            put( "nextFundingRate", nextFundingRate );
            put( "nextFundingTimestamp", null );
            put( "nextFundingDatetime", null );
            put( "previousFundingRate", null );
            put( "previousFundingTimestamp", null );
            put( "previousFundingDatetime", null );
            put( "interval", "1h" );
        }};
    }

    /**
     * @method
     * @name pacifica#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @see https://docs.pacifica.fi/api-documentation/api/rest-api/markets/get-candle-data
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents, support '1m', '3m', '5m', '15m', '30m', '1h', '2h', '4h', '8h', '12h', '1d'
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] timestamp in ms of the latest candle to fetch. 'limit' is priority
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [availble parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol2, Object... optionalArgs)
    {
        final Object symbol3 = symbol2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object symbol = symbol3;
            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(since, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchOHLCV() requires a \"since\" argument")) ;
            }
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchOHLCV() requires a \"symbol\" argument")) ;
            }
            Object defaultMaxLimit = 3950; // 4000 by docs, but in fact >~3960 returns error
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchOHLCV", "paginate", false);
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                return (this.fetchPaginatedCallDeterministic("fetchOHLCV", symbol, since, limit, timeframe, parameters, defaultMaxLimit)).join();
            }
            Object tf = this.safeString(this.timeframes, timeframe, timeframe);
            final Object finalSince = since;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "interval", tf );
                put( "start_time", finalSince );
            }};
            var requestparametersVariable = this.handleUntilOption("end_time", request, parameters);
            request = ((java.util.List<Object>) requestparametersVariable).get(0);
            parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
            Object nowMillis = this.milliseconds();
            Object until = this.safeInteger(request, "end_time");
            if (Helpers.isTrue(Helpers.isEqual(until, null)))
            {
                if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
                {
                    until = Helpers.subtract(Helpers.add(since, (Helpers.multiply(limit, (Helpers.multiply(this.parseTimeframe(tf), 1000))))), 1);
                }
                if (Helpers.isTrue(Helpers.isEqual(until, null)))
                {
                    until = Helpers.subtract(Helpers.add(since, (Helpers.multiply(defaultMaxLimit, (Helpers.multiply(this.parseTimeframe(tf), 1000))))), 1);
                }
                if (Helpers.isTrue(Helpers.isGreaterThan(until, nowMillis)))
                {
                    until = nowMillis;
                }
                Helpers.addElementToObject(request, "end_time", until);
            }
            Object response = (this.publicGetKline(this.extend(request, parameters))).join();
            //
            // {
            //   "success": true,
            //   "data": [
            //     {
            //       "t": 1748954160000,
            //       "T": 1748954220000,
            //       "s": "BTC",
            //       "i": "1m",
            //       "o": "105376",
            //       "c": "105376",
            //       "h": "105376",
            //       "l": "105376",
            //       "v": "0.00022",
            //       "n": 2
            //     }
            //   ],
            //   "error": null,
            //   "code": null
            // }
            //
            Object candles = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOHLCVs(candles, market, timeframe, since, limit);
        });

    }

    public Object parseOHLCV(Object ohlcv, Object... optionalArgs)
    {
        //
        //     {
        //       "t": 1748954160000,
        //       "T": 1748954220000,
        //       "s": "BTC",
        //       "i": "1m",
        //       "o": "105376",
        //       "c": "105376",
        //       "h": "105376",
        //       "l": "105376",
        //       "v": "0.00022",
        //       "n": 2
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeInteger(ohlcv, "t"), this.safeNumber(ohlcv, "o"), this.safeNumber(ohlcv, "h"), this.safeNumber(ohlcv, "l"), this.safeNumber(ohlcv, "c"), this.safeNumber(ohlcv, "v")));
    }

